  ('fire-eq-tech-moex-02830', 'fire-eq-tech', 'fire-eq-tech-moex-098-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '測定水成膜泡沫滅火藥劑發泡倍率，依規定所需測定器具之量筒內容積為：', '["600 ml", "1000 ml", "1200 ml", "1400 ml"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "8a14d92dbadf", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "902", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水與化學系統消防安全設備概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02831', 'fire-eq-tech', 'fire-eq-tech-moex-098-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '使用密閉式撒水頭之自動撒水設備，依規定應於管線末端配置查驗閥，下列有關查驗閥之配置規定，何 者錯誤？', '["管徑不得大於二十五公厘", "一次側應設壓力表", "二次側應設與撒水頭同等放水性能之限流孔", "距離地板面之高度不得大於二點一公尺"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "8a14d92dbadf", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "902", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水與化學系統消防安全設備概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 22, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02832', 'fire-eq-tech', 'fire-eq-tech-moex-098-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '裝置水霧滅火設備之室內停車空間，其排水設備之規定，何者錯誤？', '["車輛停駐場所地面應作不得小於百分之二以上之坡度", "車輛停駐場所，除面臨車道部分外，應設高五公分以上之地區境界堤", "滅火坑應具備油水分離裝置，並設於火災不易殃及之處所", "車道之中央或兩側應設置排水溝"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "8a14d92dbadf", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "902", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水與化學系統消防安全設備概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02833', 'fire-eq-tech', 'fire-eq-tech-moex-098-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '下列有關開放式撒水設備之規定，何者正確？', '["每一舞臺之放水區域應在五個以下", "舞臺之放水區域若在二個以上時，每一放水區域樓地板面積在100 m2以上，且鄰接之放水區域相互重 疊，使有效滅火", "供各類場所消防安全設備設置標準第十二條第一款第一目使用場所之舞臺，在十一層以上建築物之樓 層，應在最大放水區域全部撒水頭，繼續放水三十分鐘之水量以上", "一齊開放閥一次側配管裝設試驗用裝置，在該放水區域不放水情形下，能測試一齊開放閥之動作"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "8a14d92dbadf", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "902", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水與化學系統消防安全設備概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02834', 'fire-eq-tech', 'fire-eq-tech-moex-098-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '有一汽車修護廠之長、寬、高分別為40公尺、25公尺、5.5公尺，防護對象物之尺寸長、寬、高分別為 10公尺、5公尺、1.5公尺，若使用合成界面活性泡沫液，及膨脹比為350，且採全區放射方式，依「各 類場所消防安全設備設置標準」規定，其冠泡體積為多少立方公尺？', '["2000立方公尺", "3000立方公尺", "4000立方公尺", "5000立方公尺"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "8a14d92dbadf", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "902", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水與化學系統消防安全設備概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 25, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02835', 'fire-eq-tech', 'fire-eq-tech-moex-098-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '泡沫滅火設備綜合檢查中，有關蛋白質泡沫滅火藥劑25％還原時間標準值為？', '["30秒", "60秒", "90秒", "120秒"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "8a14d92dbadf", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "902", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水與化學系統消防安全設備概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02836', 'fire-eq-tech', 'fire-eq-tech-moex-098-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '某建築物之一樓為汽車修理廠，擬採用移動式泡沫滅火設備作為滅火設備，預計設置五個泡沫消防栓箱， 選用之泡沫溶液為百分之五的蛋白質泡沫，則泡沫原液儲槽內至少應存放多少公升的泡沫原液儲存量即可 符合規定？', '["90公升", "150公升", "225公升", "300公升"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "8a14d92dbadf", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "902", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水與化學系統消防安全設備概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02837', 'fire-eq-tech', 'fire-eq-tech-moex-098-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '實施室內消防栓設備放水試驗時，壓力表之進水口與瞄子前端的距離為多少？', '["30 mm", "50 mm", "瞄子口徑", "瞄子口徑的一半"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "8a14d92dbadf", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "902", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水與化學系統消防安全設備概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02838', 'fire-eq-tech', 'fire-eq-tech-moex-098-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '依「各類場所消防安全設備設置標準」之規定，裝設自動撒水設備之樓層，樓地板面積為一萬平方公尺 者，最少應設置幾個雙口形送水口？', '["一個", "二個", "三個", "四個"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "8a14d92dbadf", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "902", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水與化學系統消防安全設備概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02839', 'fire-eq-tech', 'fire-eq-tech-moex-098-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '設置開放式自動撒水設備之場所，其自動啟動裝置若係採用標示溫度在七十九℃以下之感知撒水頭時， 其最大的感知範圍在每多少平方公尺以下？', '["十平方公尺", "十五平方公尺", "二十平方公尺", "三十平方公尺"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "8a14d92dbadf", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "902", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水與化學系統消防安全設備概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL)
